from flask import Flask, request, jsonify
from datetime import datetime, timedelta

app = Flask(__name__)

# Assume the database layer is already implemented
# and provides the following functions:
# - create_list(list_name): Creates a new todo list.
# - get_list(list_id): Returns a todo list by ID.
# - update_list(list_id, list_name): Updates a todo list.
# - delete_list(list_id): Deletes a todo list.
# - create_item(list_id, item_text, due_date=None): Creates a new item in a list.
# - get_item(item_id): Returns a todo item by ID.
# - update_item(item_id, item_text=None, completed=None, due_date=None): Updates a todo item.
# - delete_item(item_id): Deletes a todo item.
# - get_items_by_list(list_id): Returns all items in a list.
# - mark_item_complete(item_id): Marks an item as complete.
# - get_overdue_items(): Returns all overdue items.
# - get_due_soon_items(days=3): Returns all items due in the next 'days' days.

# Example database functions (replace with your actual implementation)
lists = {}
items = {}
list_id_counter = 1
item_id_counter = 1

def create_list(list_name):
    global list_id_counter
    list_id = list_id_counter
    list_id_counter += 1
    lists[list_id] = {"id": list_id, "name": list_name, "items": []}
    return list_id

def get_list(list_id):
    return lists.get(list_id)

def update_list(list_id, list_name):
    if list_id in lists:
        lists[list_id]["name"] = list_name
        return True
    return False

def delete_list(list_id):
    if list_id in lists:
        del lists[list_id]
        # Also delete items associated with the list (simplified)
        for item_id in list(items.keys()):
            if items[item_id]["list_id"] == list_id:
                del items[item_id]
        return True
    return False

def create_item(list_id, item_text, due_date=None):
    global item_id_counter
    item_id = item_id_counter
    item_id_counter += 1
    if list_id in lists:
        items[item_id] = {"id": item_id, "list_id": list_id, "text": item_text, "completed": False, "due_date": due_date}
        lists[list_id]["items"].append(item_id)
        return item_id
    return None

def get_item(item_id):
    return items.get(item_id)

def update_item(item_id, item_text=None, completed=None, due_date=None):
    if item_id in items:
        if item_text is not None:
            items[item_id]["text"] = item_text
        if completed is not None:
            items[item_id]["completed"] = completed
        if due_date is not None:
            items[item_id]["due_date"] = due_date
        return True
    return False

def delete_item(item_id):
    if item_id in items:
        list_id = items[item_id]["list_id"]
        del items[item_id]
        lists[list_id]["items"].remove(item_id)
        return True
    return False

def get_items_by_list(list_id):
    if list_id in lists:
        return [items[item_id] for item_id in lists[list_id]["items"]]
    return []

def mark_item_complete(item_id):
    if item_id in items:
        items[item_id]["completed"] = True
        return True
    return False

def get_overdue_items():
    now = datetime.now()
    return [item for item_id, item in items.items() if item["due_date"] and datetime.strptime(item["due_date"], '%Y-%m-%d') < now.date() and not item["completed"]]

def get_due_soon_items(days=3):
    now = datetime.now().date()
    future_date = now + timedelta(days=days)
    return [item for item_id, item in items.items() if item["due_date"] and now <= datetime.strptime(item["due_date"], '%Y-%m-%d').date() <= future_date and not item["completed"]]


