from flask import Flask, request, jsonify
from datetime import datetime, date

app = Flask(__name__)

# Assume the database layer is already implemented and available as 'db'
# For example:
# from database import db  # Assuming 'database.py' contains the db object

# Placeholder for the database (replace with actual database interaction)
todos = {}  # {user_id: {list_id: {name: "List Name", items: [{id: 1, task: "Task 1", due_date: "2024-01-01", completed: False}, ...]}}}
next_item_id = 1


@app.route('/users/<int:user_id>/lists', methods=['POST'])
def create_list(user_id):
    """Creates a new todo list for a user."""
    data = request.get_json()
    list_name = data.get('name')

    if not list_name:
        return jsonify({'error': 'List name is required'}), 400

    if user_id not in todos:
        todos[user_id] = {}

    list_id = len(todos[user_id]) + 1  # Simple auto-increment
    todos[user_id][list_id] = {'name': list_name, 'items': []}

    return jsonify({'message': 'List created successfully', 'list_id': list_id}), 201


@app.route('/users/<int:user_id>/lists/<int:list_id>', methods=['GET'])
def get_list(user_id, list_id):
    """Retrieves a specific todo list for a user."""
    if user_id not in todos or list_id not in todos[user_id]:
        return jsonify({'error': 'List not found'}), 404

    return jsonify(todos[user_id][list_id]), 200


@app.route('/users/<int:user_id>/lists/<int:list_id>', methods=['PUT'])
def update_list(user_id, list_id):
    """Updates a todo list's name."""
    if user_id not in todos or list_id not in todos[user_id]:
        return jsonify({'error': 'List not found'}), 404

    data = request.get_json()
    new_name = data.get('name')

    if not new_name:
        return jsonify({'error': 'New list name is required'}), 400

    todos[user_id][list_id]['name'] = new_name
    return jsonify({'message': 'List updated successfully'}), 200


@app.route('/users/<int:user_id>/lists/<int:list_id>', methods=['DELETE'])
def delete_list(user_id, list_id):
    """Deletes a todo list."""
    if user_id not in todos or list_id not in todos[user_id]:
        return jsonify({'error': 'List not found'}), 404

    del todos[user_id][list_id]
    return jsonify({'message': 'List deleted successfully'}), 200


@app.route('/users/<int:user_id>/lists/<int:list_id>/items', methods=['POST'])
def create_item(user_id, list_id):
    """Creates a new item in a todo list."""
    global next_item_id
    if user_id not in todos or list_id not in todos[user_id]:
        return jsonify({'error': 'List not found'}), 404

    data = request.get_json()
    task = data.get('task')
    due_date_str = data.get('due_date')  # Expects YYYY-MM-DD

    if not task:
        return jsonify({'error': 'Task description is required'}), 400

    try:
        due_date = datetime.strptime(due_date_str, '%Y-%m-%d').date() if due_date_str else None
    except ValueError:
        return jsonify({'error': 'Invalid date format. Use YYYY-MM-DD'}), 400

    new_item = {
        'id': next_item_id,
        'task': task,
        'due_date': str(due_date) if due_date else None,
        'completed': False
    }
    todos[user_id][list_id]['items'].append(new_item)
    next_item_id += 1

    return jsonify({'message': 'Item created successfully', 'item_id': new_item['id']}), 201


@app.route('/users/<int:user_id>/lists/<int:list_id>/items/<int:item_id>', methods=['GET'])
def get_item(user_id, list_id, item_id):
    """Retrieves a specific item from a todo list."""
    if user_id not in todos or list_id not in todos[user_id]:
        return jsonify({'error': 'List not found'}), 404

    for item in todos[user_id][list_id]['items']:
        if item['id'] == item_id:
            return jsonify(item), 200

    return jsonify({'error': 'Item not found'}), 404


@app.route('/users/<int:user_id>/lists/<int:list_id>/items/<int:item_id>', methods=['PUT'])
def update_item(user_id, list_id, item_id):
    """Updates an item in a todo list."""
    if user_id not in todos or list_id not in todos[user_id]:
        return jsonify({'error': 'List not found'}), 404

    data = request.get_json()
    new_task = data.get('task')
    new_due_date_str = data.get('due_date')
    new_completed = data.get('completed')

    for item in todos[user_id][list_id]['items']:
        if item['id'] == item_id:
            if new_task:
                item['task'] = new_task

            if new_due_date_str is not None:
                try:
                    new_due_date = datetime.strptime(new_due_date_str, '%Y-%m-%d').date() if new_due_date_str else None
                    item['due_date'] = str(new_due_date) if new_due_date else None
                except ValueError:
                    return jsonify({'error': 'Invalid date format. Use YYYY-MM-DD'}), 400

            if new_completed is not None:
                item['completed'] = new_completed

            return jsonify({'message': 'Item updated successfully'}), 200

    return jsonify({'error': 'Item not found'}), 404


@app.route('/users/<int:user_id>/lists/<int:list_id>/items/<int:item_id>', methods=['DELETE'])
def delete_item(user_id, list_id, item_id):
    """Deletes an item from a todo list."""
    if user_id not in todos or list_id not in todos[user_id]:
        return jsonify({'error': 'List not found'}), 404

    items = todos[user_id][list_id]['items']
    for i, item in enumerate(items):
        if item['id'] == item_id:
            del items[i]
            todos[user_id][list_id]['items'] = items # Update the list
            return jsonify({'message': 'Item deleted successfully'}), 200

    return jsonify({'error': 'Item not found'}), 404


@app.route('/users/<int:user_id>/progress', methods=['GET'])
def get_progress(user_id):
    """Calculates and returns the overall progress for a user."""
