                self.items[item_id]["description"] = description
            if due_date is not None:
                self.items[item_id]["due_date"] = due_date
            if completed is not None:
                self.items[item_id]["completed"] = completed
            return True
        return False

    def delete_item(self, item_id):
        if item_id in self.items:
            list_id = self.items[item_id]["list_id"]
            del self.items[item_id]
            self.todo_lists[list_id]["items"].remove(item_id)
            return True
        return False

    def get_overdue_items(self):
        now = datetime.now()
        overdue = []
        for item_id, item in self.items.items():
            if item["due_date"] and not item["completed"]:
                due_date = datetime.strptime(item["due_date"], "%Y-%m-%d")
                if due_date < now:
                    overdue.append(item)
        return overdue

    def get_due_items(self):
        now = datetime.now()
        due = []
        for item_id, item in self.items.items():
            if item["due_date"] and not item["completed"]:
                due_date = datetime.strptime(item["due_date"], "%Y-%m-%d")
                if due_date >= now:
                    due.append(item)
        return due

