import base64
import time
import requests
import json

class APIClient:
    def __init__(self, api_key, api_secret, base_url="https://api.example.com"):
        self.api_key = api_key
        self.api_secret = api_secret
        self.base_url = base_url

    def _generate_signature(self, path, method, body=None, timestamp=None):
        """Generates an HMAC signature for the API request."""
        if timestamp is None:
            timestamp = str(int(time.time()))

        message = timestamp + method + path
        if body:
            message += json.dumps(body, separators=(',', ':'))  # Consistent JSON formatting

        hmac_obj = hmac.new(
            self.api_secret.encode('utf-8'),
            message.encode('utf-8'),
            hashlib.sha256
        )
        signature = base64.b64encode(hmac_obj.digest()).decode('utf-8')
        return signature, timestamp

    def _make_request(self, path, method, body=None, headers=None):
        """Makes an API request with authentication."""
        url = self.base_url + path

        signature, timestamp = self._generate_signature(path, method, body)

        default_headers = {
            "API-Key": self.api_key,
            "API-Signature": signature,
            "API-Timestamp": timestamp,
            "Content-Type": "application/json"
        }

        if headers:
            default_headers.update(headers)

        try:
            if method == "GET":
                response = requests.get(url, headers=default_headers)
            elif method == "POST":
                response = requests.post(url, headers=default_headers, json=body)
            elif method == "PUT":
                response = requests.put(url, headers=default_headers, json=body)
            elif method == "DELETE":
                response = requests.delete(url, headers=default_headers)
            else:
                raise ValueError(f"Unsupported HTTP method: {method}")

            response.raise_for_status()  # Raise HTTPError for bad responses (4xx or 5xx)
            return response.json()

        except requests.exceptions.RequestException as e:
            print(f"API request failed: {e}")
            if response is not None:
                try:
