        """Example POST request."""
        return self._make_request(endpoint, "POST", body=data)

    def update_data(self, endpoint, data):
        """Example PUT request."""
        return self._make_request(endpoint, "PUT", body=data)

    def delete_data(self, endpoint):
        """Example DELETE request."""
        return self._make_request(endpoint, "DELETE")

